#!/usr/bin/env perl
use strict;
use warnings;
use File::Path qw(make_path);
use File::Basename qw(dirname);

my $MINIGIT_DIR = '.minigit';

sub minihash {
    my ($data) = @_;
    my $h = 1469598103934665603;
    # Use Math::BigInt-like manual 64-bit arithmetic via 'use integer' won't work
    # because Perl's integers may be 64-bit signed. We need unsigned 64-bit.
    # On 64-bit Perl, we can use bitwise ops carefully.
    my $mod = 2**64;
    for my $b (unpack('C*', $data)) {
        $h ^= $b;
        # Multiply and mod 2^64 using no overflow beyond what Perl can handle
        # Use the 'use integer' pragma won't help for unsigned.
        # On 64-bit systems, Perl NV (double) loses precision above 2^53.
        # We need to do the multiplication in parts.
        my $lo = $h & 0xFFFFFFFF;
        my $hi = ($h >> 32) & 0xFFFFFFFF;
        my $factor = 1099511628211;
        my $flo = $factor & 0xFFFFFFFF;
        my $fhi = ($factor >> 32) & 0xFFFFFFFF;
        # Full multiplication: (hi*2^32 + lo) * (fhi*2^32 + flo)
        # We only need the lower 64 bits.
        # lo*flo can be up to ~2^64, need to split further
        my $ll = ($lo & 0xFFFF) * $flo;
        my $lh = ($lo >> 16) * $flo;
        my $r0 = ($ll & 0xFFFF);
        my $r1 = (($ll >> 16) + ($lh & 0xFFFF)) & 0xFFFF;
        my $carry = (($ll >> 16) + ($lh & 0xFFFF)) >> 16;
        my $r2 = (($lh >> 16) + $carry) & 0xFFFF;
        my $r3_part1 = ($lh >> 16) + $carry;
        # Actually this is getting complex. Let me use a simpler approach.
        # Since we're on 64-bit Perl, use 'use integer' for wrapping arithmetic.
        # Perl's 'use integer' gives signed 64-bit, but XOR and the lower bits
        # of multiplication are the same for signed/unsigned.
        $h = _mul_mod64($h, $factor);
    }
    return sprintf('%016x', $h);
}

sub _mul_mod64 {
    my ($a, $b) = @_;
    # Split into 32-bit halves to avoid floating point precision loss
    my $a_lo = $a & 0xFFFFFFFF;
    my $a_hi = ($a >> 32) & 0xFFFFFFFF;
    my $b_lo = $b & 0xFFFFFFFF;
    my $b_hi = ($b >> 32) & 0xFFFFFFFF;

    # We need (a_hi * 2^32 + a_lo) * (b_hi * 2^32 + b_lo) mod 2^64
    # = a_lo*b_lo + (a_lo*b_hi + a_hi*b_lo)*2^32   (mod 2^64)
    # a_hi*b_hi * 2^64 vanishes mod 2^64

    # a_lo * b_lo: up to ~2^64, split further into 16-bit parts
    my $al_lo = $a_lo & 0xFFFF;
    my $al_hi = ($a_lo >> 16) & 0xFFFF;
    my $bl_lo = $b_lo & 0xFFFF;
    my $bl_hi = ($b_lo >> 16) & 0xFFFF;

    my $p0 = $al_lo * $bl_lo;
    my $p1 = $al_lo * $bl_hi;
    my $p2 = $al_hi * $bl_lo;
    my $p3 = $al_hi * $bl_hi;

    # Combine: result = p3*2^32 + (p1+p2)*2^16 + p0
    my $mid = $p1 + $p2;  # at most ~2^33
    my $low32 = ($p0 + (($mid & 0xFFFF) << 16)) & 0xFFFFFFFF;
    my $high32 = ($p3 + ($mid >> 16) + (($p0 + (($mid & 0xFFFF) << 16)) >> 32)) & 0xFFFFFFFF;

    # Cross terms: (a_lo*b_hi + a_hi*b_lo) * 2^32, only lower 32 bits matter
    my $cross = (($a_lo * $b_hi + $a_hi * $b_lo) & 0xFFFFFFFF);
    $high32 = ($high32 + $cross) & 0xFFFFFFFF;

    return ($high32 << 32) | $low32;
}

sub read_file {
    my ($path) = @_;
    open my $fh, '<:raw', $path or return '';
    local $/;
    my $content = <$fh>;
    close $fh;
    return defined $content ? $content : '';
}

sub write_file {
    my ($path, $content) = @_;
    open my $fh, '>:raw', $path or die "Cannot write $path: $!\n";
    print $fh $content;
    close $fh;
}

sub cmd_init {
    if (-d $MINIGIT_DIR) {
        print "Repository already initialized\n";
        return;
    }
    make_path("$MINIGIT_DIR/objects");
    make_path("$MINIGIT_DIR/commits");
    write_file("$MINIGIT_DIR/index", '');
    write_file("$MINIGIT_DIR/HEAD", '');
}

sub cmd_add {
    my ($file) = @_;
    unless (defined $file && -e $file) {
        print "File not found\n";
        exit 1;
    }
    my $content = read_file($file);
    my $hash = minihash($content);
    write_file("$MINIGIT_DIR/objects/$hash", $content);

    # Add to index if not already present
    my $index = read_file("$MINIGIT_DIR/index");
    my @lines = grep { $_ ne '' } split /\n/, $index;
    unless (grep { $_ eq $file } @lines) {
        push @lines, $file;
        write_file("$MINIGIT_DIR/index", join("\n", @lines) . "\n");
    }
