unless (defined $cmd) {
    print "Usage: minigit <command>\n";
    exit 1;
}

if ($cmd eq 'init') {
    cmd_init();
} elsif ($cmd eq 'add') {
    cmd_add(shift @ARGV);
} elsif ($cmd eq 'commit') {
    # Parse -m "message"
    my $flag = shift @ARGV;
    my $message = shift @ARGV;
    cmd_commit($message);
